css:
.receipt {
    font-family: 'Courier New', monospace;
    width: 80mm;
    margin: 0 auto;
}

.receipt-header {
    text-align: center;
    border-bottom: 2px solid #000;
    padding-bottom: 10px;
    margin-bottom: 15px;
}

.restaurant-name {
    font-size: 24px;
    font-weight: bold;
}

.restaurant-name-ar {
    font-size: 20px;
    direction: rtl;
}

.receipt-info {
    font-size: 12px;
    margin: 5px 0;
}

.receipt-divider {
    border-top: 1px dashed #000;
    margin: 10px 0;
}

.order-info {
    margin: 10px 0;
}

.order-info table {
    width: 100%;
    font-size: 12px;
}

.items-table {
    width: 100%;
    border-collapse: collapse;
    margin: 15px 0;
}

.items-table th {
    border-bottom: 1px solid #000;
    text-align: left;
    padding: 5px 0;
    font-size: 12px;
}

.items-table td {
    padding: 8px 0;
    font-size: 12px;
    vertical-align: top;
}

.items-table .item-name {
    max-width: 150px;
}

.items-table .qty {
    text-align: center;
    width: 30px;
}

.items-table .amount {
    text-align: right;
    width: 60px;
}

.item-modifiers {
    font-size: 10px;
    color: #666;
    margin-left: 10px;
}

.totals-section {
    margin-top: 15px;
}

.totals-table {
    width: 100%;
    font-size: 12px;
}

.totals-table td {
    padding: 3px 0;
}

.totals-table .label {
    text-align: left;
}

.totals-table .value {
    text-align: right;
}

.grand-total {
    font-size: 16px;
    font-weight: bold;
    border-top: 2px solid #000;
    border-bottom: 2px solid #000;
    padding: 10px 0;
}

.receipt-footer {
    text-align: center;
    margin-top: 20px;
    padding-top: 10px;
    border-top: 1px dashed #000;
}

.thank-you {
    font-size: 14px;
    font-weight: bold;
}

.thank-you-ar {
    font-size: 14px;
    direction: rtl;
}

.qr-code {
    margin: 15px auto;
    text-align: center;
}

.vat-info {
    font-size: 10px;
    margin-top: 10px;
}

@media print {
    body {
        width: 80mm;
        margin: 0;
        padding: 2mm;
    }
}

html:
{% set settings = get_restaurant_settings() %}
{% set currency = settings.currency_symbol or "SAR" %}
<div class="receipt">
    <div class="receipt-header">
        {% if settings.restaurant_logo %}
        <img src="{{ settings.restaurant_logo }}" style="max-width: 150px; margin-bottom: 10px;">
        {% endif %}
        <div class="restaurant-name">{{ settings.restaurant_name or "Restaurant" }}</div>
        {% if settings.restaurant_name_ar %}
        <div class="restaurant-name-ar">{{ settings.restaurant_name_ar }}</div>
        {% endif %}
        <div class="receipt-info">
            {{ settings.address or "" }}<br>
            {% if settings.phone %}Tel: {{ settings.phone }}{% endif %}
        </div>
        {% if settings.vat_number %}
        <div class="receipt-info">VAT No: {{ settings.vat_number }}</div>
        {% endif %}
    </div>
    <div class="order-info">
        <table>
            <tr><td><strong>Order #:</strong></td><td>{{ doc.name }}</td></tr>
            <tr><td><strong>Date:</strong></td><td>{{ doc.creation }}</td></tr>
            {% if doc.restaurant_table %}
            <tr><td><strong>Table:</strong></td><td>{{ doc.table_number or doc.restaurant_table }}</td></tr>
            {% endif %}
            <tr><td><strong>Type:</strong></td><td>{{ doc.order_type }}</td></tr>
            {% if doc.waiter %}
            <tr><td><strong>Server:</strong></td><td>{{ doc.waiter }}</td></tr>
            {% endif %}
        </table>
    </div>
    <div class="receipt-divider"></div>
    <table class="items-table">
        <thead><tr><th class="qty">Qty</th><th class="item-name">Item</th><th class="amount">Amount</th></tr></thead>
        <tbody>
            {% for item in doc.items %}
            <tr>
                <td class="qty">{{ item.qty }}</td>
                <td class="item-name">{{ item.item_name }}{% if item.modifiers %}<div class="item-modifiers">{{ item.modifiers }}</div>{% endif %}</td>
                <td class="amount">{{ currency }} {{ "%.2f"|format(item.amount or 0) }}</td>
            </tr>
            {% endfor %}
        </tbody>
    </table>
    <div class="receipt-divider"></div>
    <div class="totals-section">
        <table class="totals-table">
            <tr><td class="label">Subtotal:</td><td class="value">{{ currency }} {{ "%.2f"|format(doc.subtotal or 0) }}</td></tr>
            {% if doc.discount_amount %}<tr><td class="label">Discount:</td><td class="value">-{{ currency }} {{ "%.2f"|format(doc.discount_amount) }}</td></tr>{% endif %}
            {% if doc.tax_amount %}<tr><td class="label">VAT:</td><td class="value">{{ currency }} {{ "%.2f"|format(doc.tax_amount) }}</td></tr>{% endif %}
            {% if doc.service_charge %}<tr><td class="label">Service Charge:</td><td class="value">{{ currency }} {{ "%.2f"|format(doc.service_charge) }}</td></tr>{% endif %}
            <tr class="grand-total"><td class="label">TOTAL:</td><td class="value">{{ currency }} {{ "%.2f"|format(doc.grand_total or 0) }}</td></tr>
        </table>
    </div>
    {% if doc.payment_method %}
    <div class="receipt-divider"></div>
    <div class="payment-info"><strong>Payment:</strong> {{ doc.payment_method }}</div>
    {% endif %}
    <div class="receipt-footer">
        <div class="thank-you">Thank You!</div>
        <div class="thank-you-ar">شكراً لزيارتكم</div>
        {% if settings.receipt_footer %}<div class="receipt-info" style="margin-top: 10px;">{{ settings.receipt_footer }}</div>{% endif %}
        {% if settings.vat_number %}<div class="vat-info">Tax Invoice / فاتورة ضريبية</div>{% endif %}
    </div>
</div>
